+  }
+  const target = parseDestination(destinationArea);
+  if (target === null) {
+    return null;
+  }
+
+  return {end: destinationEnd + 1, image, label: unescapeMarkdown(label), target};
+}
+
+function findBalancedEnd(text: string, start: number, open: string, close: string): number | null {
+  let depth = 0;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+      continue;
+    }
+    if (text[index] === '\
') {
+      return null;
+    }
+    if (text[index] === open) {
+      depth++;
+    } else if (text[index] === close && --depth === 0) {
+      return index;
+    }
+  }
+  return null;
+}
+
+function parseDestination(destinationArea: string): string | null {
+  const trimmed = destinationArea.trim();
+  if (trimmed.startsWith('<')) {
+    const close = findUnescapedCharacter(trimmed, '>', 1);
+    if (close === -1 || trimmed.slice(close + 1).trim() !== '') {
+      return null;
+    }
+    return unescapeMarkdown(trimmed.slice(1, close));
+  }
+
+  let depth = 0;
+  for (let index = 0; index < destinationArea.length; index++) {
+    const character = destinationArea[index];
+    if (character === '\\\') {
+      index++;
+    } else if (character === '(') {
+      depth++;
+    } else if (character === ')') {
+      depth--;
+    } else if (/\\s/.test(character) && depth === 0) {
+      return null;
+    }
+  }
+  return unescapeMarkdown(destinationArea);
+}
+
+function findUnescapedCharacter(text: string, character: string, start: number): number {
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === character) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function unescapeMarkdown(text: string): string {
+  return text.replace(/\\\\(.)/g, '$1');
+}
